#!/usr/bin/env node
/**
 * scripts/fix-demo-bundles.js
 * Fixes EN/DE/FR bundles and creates NL bundle.
 * Run: node scripts/fix-demo-bundles.js
 */
const fs = require('fs');
const path = require('path');
const BUNDLES_DIR = path.join(__dirname, '../data/demo-bundles');

function load(lang) {
  return JSON.parse(fs.readFileSync(path.join(BUNDLES_DIR, `${lang}.json`), 'utf8'));
}
function save(lang, bundle) {
  fs.writeFileSync(path.join(BUNDLES_DIR, `${lang}.json`), JSON.stringify(bundle, null, 2));
  const kb = (fs.statSync(path.join(BUNDLES_DIR, `${lang}.json`)).size / 1024).toFixed(1);
  console.log(`✓ ${lang}.json  (${kb} KB)`);
}

