      { id:'tmpl_nl_001', title:'Informatiebeveiligingsbeleid', type:'Policy', status:'approved', language:'nl', version:2, content:'Dit Informatiebeveiligingsbeleid definieert het kader voor de bescherming van informatiemiddelen van Demo BV. Het is van toepassing op alle medewerkers, aannemers en derden. Het beleid is afgestemd op ISO 27001:2022 en wordt jaarlijks herzien.', linkedControls:['ISO-5.1'], applicableEntities:[], attachments:[], nextReviewDate:'2027-01-01', createdAt:'2025-03-01T09:00:00.000Z', updatedAt:'2026-01-10T09:00:00.000Z', createdBy:'admin' },
      { id:'tmpl_nl_002', title:'Procedure voor incidentrespons', type:'Procedure', status:'approved', language:'nl', version:1, content:'Deze procedure beschrijft het proces voor detectie, classificatie, escalatie en afhandeling van informatiebeveiligingsincidenten. Ernst-niveaus: Kritiek, Hoog, Medium, Laag. Escalatiepad: Servicedesk → CISO → Directie.', linkedControls:['ISO-5.26'], applicableEntities:[], attachments:[], nextReviewDate:'2027-01-01', createdAt:'2025-06-01T09:00:00.000Z', updatedAt:'2026-01-10T09:00:00.000Z', createdBy:'admin' },
      { id:'tmpl_nl_003', title:'Beleid voor acceptabel gebruik van IT-middelen', type:'Policy', status:'approved', language:'nl', version:1, content:'Dit beleid beschrijft de regels voor aanvaardbaar gebruik van IT-systemen, apparaten en gegevens van Demo BV door medewerkers en contractors. Verboden gebruik wordt uitdrukkelijk vermeld. Overtreding kan leiden tot disciplinaire maatregelen.', linkedControls:['ISO-5.10'], applicableEntities:[], attachments:[], nextReviewDate:'2027-01-01', createdAt:'2025-09-01T09:00:00.000Z', updatedAt:'2026-01-10T09:00:00.000Z', createdBy:'admin' }
