    'guidance.json': [
      { id:'guidance_nl_001', title:'ISMS Build – Systeemhandboek', category:'systemhandbuch', content:'# ISMS Build – Systeemhandboek\n\nDit handboek beschrijft de architectuur, configuratie en het beheer van het ISMS Build-platform voor Demo BV.\n\n## Modules\n- Risicobeheer\n- AVG & Gegevensbescherming\n- Leveranciersbeheer\n- Bedrijfscontinuïteit\n\n## Toegangsbeheer\nGebaseerd op rolgebaseerde toegangscontrole (RBAC).', status:'published', owner:'CISO', linkedControls:[], linkedPolicies:[], attachments:[], createdAt:'2026-01-01T09:00:00.000Z', updatedAt:'2026-01-01T09:00:00.000Z', createdBy:'admin' },
      { id:'guidance_nl_002', title:'Rollen en verantwoordelijkheden', category:'rollen', content:'# Rollen en verantwoordelijkheden\n\n## CISO\nVerantwoordelijk voor de algehele informatiebeveiliging en het ISMS.\n\n## FG (Functionaris Gegevensbescherming)\nToezicht op AVG-naleving en contactpersoon voor de Autoriteit Persoonsgegevens.\n\n## IT Manager\nTechnische uitvoering van beveiligingsmaatregelen.\n\n## Afdelingshoofden\nEigenaarschap van risico\'s en beleidsimplementatie binnen hun afdeling.', status:'published', owner:'CISO', linkedControls:[], linkedPolicies:[], attachments:[], createdAt:'2026-01-01T09:00:00.000Z', updatedAt:'2026-01-01T09:00:00.000Z', createdBy:'admin' }
    ],
